// Codegen — emit a Deno-importable snapshot of textileVocabulary's canonical
// names + aliases for the edge functions to consume. Edge functions can't
// import from src/ (different module resolution + the Supabase deploy
// bundles only the function dir), so this script bridges the gap.
//
// Run automatically via `npm run codegen:vocab` before
// `node scripts/deploy-edge-functions.mjs`. The generated file is
// committed to the repo so deploys don't depend on a clean working tree.
//
// Source of truth: src/lib/textileVocabulary.js
// Output:          supabase/functions/_shared/vocab.generated.ts
//
// If you change the source, re-run this script and commit both files
// together.

import { writeFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";

const here = dirname(fileURLToPath(import.meta.url));
const repo = join(here, "..");

// Dynamic import to leverage Node's native ESM resolution. textileVocabulary
// has no imports of its own so this works without Vite's `@/` alias.
const vocab = await import(
  // file:// URI so Windows paths work
  new URL(`file:///${join(repo, "src/lib/textileVocabulary.js").replace(/\\/g, "/")}`).href
);

const {
  CATEGORIES,
  PRODUCT_FAMILIES,
  allCanonicals,
  _internals,
} = vocab;

// Per-category lists (canonicals + every alias). Sorted so the generated
// file is diff-friendly.
function categoryEntries(cat) {
  const idx = _internals.REVERSE_INDEX[cat];
  if (!idx) return { canonicals: [], aliases: [] };
  const canonSet = new Set(idx.values());
  const canonicals = Array.from(canonSet).sort();
  const aliases = Array.from(idx.keys())
    .filter((a) => !canonSet.has(idx.get(a)) || a !== idx.get(a).toLowerCase())
    .sort();
  return { canonicals, aliases };
}

const lines = [];
lines.push("// AUTO-GENERATED by scripts/generate-vocab-edge.mjs");
lines.push("// Source of truth: src/lib/textileVocabulary.js");
lines.push("// DO NOT EDIT BY HAND — re-run the codegen script and commit.");
lines.push("");
lines.push(`export const CATEGORIES = ${JSON.stringify(CATEGORIES)} as const;`);
lines.push(`export const PRODUCT_FAMILIES = ${JSON.stringify(PRODUCT_FAMILIES)} as const;`);
lines.push("");

for (const cat of CATEGORIES) {
  const { canonicals, aliases } = categoryEntries(cat);
  const upperCat = cat.toUpperCase();
  lines.push(`// ── ${cat} ────────────────────────────────────────────────`);
  lines.push(`export const ${upperCat}_CANONICALS = ${JSON.stringify(canonicals)} as const;`);
  lines.push(`export const ${upperCat}_ALIASES = ${JSON.stringify(aliases)} as const;`);
  lines.push("");
}

// Forbidden-word lookup for fabric_consumption.component_type — used by the
// extraction prompt to reject fabric descriptors that landed in the wrong
// column. Combines fibre + fabric_type + measurement-keyword text.
const fibreWords = categoryEntries("fibre").aliases.concat(categoryEntries("fibre").canonicals.map(c => c.toLowerCase()));
const fabricTypeWords = categoryEntries("fabric_type").aliases.concat(categoryEntries("fabric_type").canonicals.map(c => c.toLowerCase()));
const forbiddenInComponentType = Array.from(new Set([...fibreWords, ...fabricTypeWords])).sort();
lines.push(`// Words that are NEVER valid component_type values — they belong in fabric_type.`);
lines.push(`export const FABRIC_FORBIDDEN_IN_COMPONENT_TYPE = ${JSON.stringify(forbiddenInComponentType)} as const;`);
lines.push("");

// Tiny helper Deno-side: case-insensitive membership check. Mirrors
// isInCategory("part", x) without dragging the whole REVERSE_INDEX over.
lines.push(`/** Case-insensitive membership check across canonicals + aliases for a category. */`);
lines.push(`export function isInCategory(`);
lines.push(`  category: keyof typeof _ALL_BY_CATEGORY,`);
lines.push(`  value: string,`);
lines.push(`): boolean {`);
lines.push(`  if (!value) return false;`);
lines.push(`  const v = value.toString().toLowerCase().trim().replace(/\\s+/g, " ");`);
lines.push(`  if (!v) return false;`);
lines.push(`  const list = _ALL_BY_CATEGORY[category];`);
lines.push(`  return list?.has(v) ?? false;`);
lines.push(`}`);
lines.push("");

// Pre-computed lookup map per category. Keys are lower-case;
// values are the canonical (unused for membership; included so Deno-side
// callers can also do canonical lookup if they ever need it).
lines.push(`const _ALL_BY_CATEGORY: Record<string, Set<string>> = {`);
for (const cat of CATEGORIES) {
  const idx = _internals.REVERSE_INDEX[cat];
  const keys = idx ? Array.from(idx.keys()).sort() : [];
  lines.push(`  ${cat}: new Set(${JSON.stringify(keys)}),`);
}
lines.push(`};`);
lines.push("");

// Edge functions can't import from siblings outside their own dir under
// the Supabase deploy API (each function uploads only its own files).
// So write a copy of the vocab snapshot into every function dir that
// needs it. Update this list when a new function starts using vocab.
const TARGETS = [
  "supabase/functions/extract-document/_vocab.generated.ts",
  // Add classify-components / others here as they migrate.
];

const out = lines.join("\n");
for (const rel of TARGETS) {
  const outPath = join(repo, rel);
  writeFileSync(outPath, out, "utf8");
  console.log(`✓ Wrote ${outPath} (${out.length} bytes)`);
}
console.log(`  Categories: ${CATEGORIES.length}, families: ${PRODUCT_FAMILIES.length}`);
